impl Solution { pub fn max_moves(grid: Vec<Vec<i32>>) -> i32 { let (m, n) = (grid.len(), grid[0].len()); let mut black_q: std::collections::HashSet<usize> = (0..m).collect(); for j in 0..n-1 { let mut black_next = std::collections::HashSet::new(); for &r in &black_q { for nr in r.saturating_sub(1)..=(r+1).min(m-1) { if grid[nr][j+1] > grid[r][j] { black_next.insert(nr); } } } if black_next.is_empty() { return j as i32; } black_q = black_next; } n as i32 - 1 } }